  ('dietitian-moex-06940', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '社區營養需求評估的敘述，下列何者錯誤？ 應訂定營養問題的優先次序 可使用三角檢驗法（triangulation）來進行評估 可由政府或相關單位公布的現有資料開始分析（如：人口統計學） 聚焦社區民眾營養健康問題，避免浪費時間於非直接相關因素（如：民眾的價值觀）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
